function getRoyaltiesReceiver(address _contractAddress, uint256 _tokenId) external view returns(address royaltiesReceiver) {
  bool success;
  bytes memory res;

  (success, res) = _contractAddress.staticcall(
      abi.encodeWithSelector(
          IERC721CollectionV2(_contractAddress).decodeTokenId.selector,
          _tokenId
      )
  );

  if (!success) {
    return royaltiesReceiver;
  }

  (uint256 itemId,) = abi.decode(res, (uint256, uint256));

  (success, res) = _contractAddress.staticcall(
      abi.encodeWithSelector(
          IERC721CollectionV2(_contractAddress).items.selector,
          itemId
      )
  );

  if (success) {
    // Get item beneficiary
    (,,,,royaltiesReceiver,,) = abi.decode(res, (string, uint256, uint256, uint256, address, string, string));
  }

  if (royaltiesReceiver == address(0)) {
    // If still the zero address, use the creator
     (success, res) = _contractAddress.staticcall(
      abi.encodeWithSelector(
          IERC721CollectionV2(_contractAddress).creator.selector
      ));

      if (!success) {
        return royaltiesReceiver;
      }

      royaltiesReceiver = abi.decode(res, (address));
  }

  return royaltiesReceiver;
}

function getBitmapForInterval(
  uint256 startBlock,
  uint256 endBlock
) public view onlyL1 returns (bytes32) {
  require(endBlock >= startBlock, "endBlock must be greater or equal than startBlock");
  // The signature bitmap for block N is stored in block N+1.
  // The latest block is `block.number - 1`, which stores the signature bitmap for
  // `block.number - 2`.
  uint256 lastBlockWithSignatureBitmap = block.number.sub(2);
  require(
    endBlock <= lastBlockWithSignatureBitmap,
    "the signature bitmap for endBlock is not yet available"
  );
  uint256 epochSize = getEpochSize();
  require(
    block.number.sub(startBlock) < epochSize.mul(4),
    "startBlock must be within 4 epochs of the current head"
  );
  require(
    epochNumberOfBlock(startBlock, epochSize) == epochNumberOfBlock(endBlock, epochSize),
    "startBlock and endBlock must be in the same epoch"
  );

  bytes32 bitmap;
  for (
    uint256 blockNumber = startBlock;
    blockNumber <= endBlock;
    blockNumber = blockNumber.add(1)
  ) {
    // The canonical signatures for block N are stored in the parent seal bitmap for block N+1.
    bitmap |= getParentSealBitmap(blockNumber.add(1));
  }

  return bitmap;
}

function performSlashing(
  address validator,
  address recipient,
  uint256 startBlock,
  uint256 groupMembershipHistoryIndex,
  address[] memory validatorElectionLessers,
  address[] memory validatorElectionGreaters,
  uint256[] memory validatorElectionIndices,
  address[] memory groupElectionLessers,
  address[] memory groupElectionGreaters,
  uint256[] memory groupElectionIndices
) internal {
  ILockedGold lockedGold = getLockedGold();
  lockedGold.slash(
    validator,
    slashingIncentives.penalty,
    recipient,
    slashingIncentives.reward,
    validatorElectionLessers,
    validatorElectionGreaters,
    validatorElectionIndices
  );
  address group = groupMembershipAtBlock(validator, startBlock, groupMembershipHistoryIndex);
  assert(group != address(0));
  lockedGold.slash(
    group,
    slashingIncentives.penalty,
    recipient,
    slashingIncentives.reward,
    groupElectionLessers,
    groupElectionGreaters,
    groupElectionIndices
  );
  IValidators validators = getValidators();
  validators.forceDeaffiliateIfValidator(validator);
  validators.halveSlashingMultiplier(group);
}

function settleTakerSell(MatchResult[] memory results, OrderAddressSet memory orderAddressSet) internal {
    uint256 totalTakerQuoteTokenFilledAmount = 0;

    for (uint256 i = 0; i < results.length; i++) {
        transferFrom(
            orderAddressSet.baseToken,
            results[i].taker,
            results[i].maker,
            results[i].baseTokenFilledAmount
        );

        transferFrom(
            orderAddressSet.quoteToken,
            results[i].maker,
            orderAddressSet.relayer,
            results[i].quoteTokenFilledAmount.
            add(results[i].makerFee).
            add(results[i].makerGasFee).
            sub(results[i].makerRebate)
        );

        totalTakerQuoteTokenFilledAmount = totalTakerQuoteTokenFilledAmount.add(
            results[i].quoteTokenFilledAmount.sub(results[i].takerFee)
        );

        emitMatchEvent(results[i], orderAddressSet);
    }

    transferFrom(
        orderAddressSet.quoteToken,
        orderAddressSet.relayer,
        results[0].taker,
        totalTakerQuoteTokenFilledAmount.sub(results[0].takerGasFee)
    );
}

function callWithOffchainLookupPropagation(
    address target,
    bytes memory name,
    bytes memory innerdata,
    bytes memory data
) internal view returns (bytes memory) {
    if (!target.isContract()) {
        revertWithDefaultOffchainLookup(name, innerdata);
    }

    bool result = LowLevelCallUtils.functionStaticCall(
        address(target),
        data
    );
    uint256 size = LowLevelCallUtils.returnDataSize();
    if (result) {
        bytes memory returnData = LowLevelCallUtils.readReturnData(0, size);
        return abi.decode(returnData, (bytes));
    }
    // Failure
    if (size >= 4) {
        bytes memory errorId = LowLevelCallUtils.readReturnData(0, 4);
        if (bytes4(errorId) == OffchainLookup.selector) {
            // Offchain lookup. Decode the revert message and create our own that nests it.
            bytes memory revertData = LowLevelCallUtils.readReturnData(
                4,
                size - 4
            );
            handleOffchainLookupError(revertData, target, name);
        }
    }
    LowLevelCallUtils.propagateRevert();
}

function pendingStakeAndFees(address _delegator, uint256 _endRound)
        internal
        view
        returns (uint256 stake, uint256 fees)
    {
        Delegator storage del = delegators[_delegator];
        Transcoder storage t = transcoders[del.delegateAddress];

        fees = del.fees;
        stake = del.bondedAmount;

        uint256 startRound = del.lastClaimRound.add(1);
        address delegateAddr = del.delegateAddress;
        bool isTranscoder = _delegator == delegateAddr;

        // Make sure there is a round to claim i.e. end round - (start round - 1) > 0
        if (startRound <= _endRound) {
            (stake, fees) = delegatorCumulativeStakeAndFees(t, startRound.sub(1), _endRound, stake, fees);
        }
        // cumulativeRewards and cumulativeFees will track *all* rewards/fees earned by the transcoder
        // so it is important that this is only executed with the end round as the current round or else
        // the returned stake and fees will reflect rewards/fees earned in the future relative to the end round
        if (isTranscoder) {
            stake = stake.add(t.cumulativeRewards);
            fees = fees.add(t.cumulativeFees);
        }

        return (stake, fees);
    }

function afterAllHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    override
{
    (address recipient_,) = getTermsInfo(_terms);
    bytes32 hashKey_ = _getHashKey(msg.sender, recipient_);

    balanceTracker[hashKey_].validationRemaining--;

    // Only validate on the last afterAllHook if there are multiple enforcers tracking the same recipient pair
    if (balanceTracker[hashKey_].validationRemaining > 0) return;

    BalanceTracker memory balanceTracker_ = balanceTracker[hashKey_];

    require(
        recipient_.balance >= balanceTracker_.balanceBefore + balanceTracker_.expectedIncrease,
        "NativeTokenMultiOperationIncreaseBalanceEnforcer:insufficient-balance-increase"
    );

    emit ValidatedBalance(msg.sender, recipient_, balanceTracker_.expectedIncrease);

    delete balanceTracker[hashKey_];
}

function requestLiquidation(uint256 tokenId) public override onlyRouter returns (bool) {

    uint256 liquidationTimerEnd = liquidationRequestTimes[tokenId] + liquidationGracePeriod;
    uint256 liquidationTimerExpired = liquidationTimerEnd + liquidationClaimPeriod;

    if (liquidationTimerEnd > block.timestamp) {
        revert("Timer already started");
    } else if (liquidationTimerExpired < block.timestamp) {
        liquidationRequestTimes[tokenId] = block.timestamp;
        emit AccountLiquidationStarted(tokenId);
        return false;

    } else {

        uint256 accountLevel = accountLevels[tokenId];

        delete referralLinks[keccak256(abi.encodePacked(referralStrings[tokenId]))];
        delete referralStrings[tokenId];
        liquidatedAccounts[tokenId] = true;

        string[] memory URLs = new string[](accountLevel + 1);
        for(uint256 x = 0; x < URLs.length; x++) {
            URLs[x] = levelSettings[x].unstakedURL;
        }

        IUnstakedNFTMinter(contractRegistry.getContractAddress(UNSTAKED_NFTS_HASH)).mintUnstakedTokens(ownerOf(tokenId), URLs);

        _burn(tokenId);

        emit AccountLiquidated(tokenId);
        return true;
    }
}

function recoverAddress(address lostAccount, address newAccount) public virtual onlyAgent returns (euint64) {
    require(lostAccount != newAccount, ERC7984RwaSelfRecoveryNotAllowed());

    euint64 balance = confidentialBalanceOf(lostAccount);
    euint64 lostFrozenBalance = confidentialFrozen(lostAccount);

    if (FHE.isInitialized(lostFrozenBalance)) {
        _setConfidentialFrozen(lostAccount, euint64.wrap(0));
    }

    euint64 tokensRecovered = _transfer(lostAccount, newAccount, balance);
    FHE.allow(tokensRecovered, msg.sender);

    if (FHE.isInitialized(lostFrozenBalance)) {
        _setConfidentialFrozen(
            newAccount,
            FHESafeMath.saturatingAdd(confidentialFrozen(newAccount), FHE.min(tokensRecovered, lostFrozenBalance))
        );
        _setConfidentialFrozen(lostAccount, FHESafeMath.saturatingSub(lostFrozenBalance, tokensRecovered));
    }

    Restriction restriction = getRestriction(lostAccount);
    if (restriction == Restriction.BLOCKED) {
        _blockUser(newAccount);
    }

    emit TokensRecovered(lostAccount, newAccount, tokensRecovered);

    return tokensRecovered;
}

function _mintConsecutive(address to, uint96 batchSize) internal virtual returns (uint96) {
    uint96 next = _nextConsecutiveId();

    // minting a batch of size 0 is a no-op
    if (batchSize > 0) {
        if (address(this).code.length > 0) {
            revert ERC721ForbiddenBatchMint();
        }
        if (to == address(0)) {
            revert ERC721InvalidReceiver(address(0));
        }

        uint256 maxBatchSize = _maxBatchSize();
        if (batchSize > maxBatchSize) {
            revert ERC721ExceededMaxBatchMint(batchSize, maxBatchSize);
        }

        // push an ownership checkpoint & emit event
        uint96 last = next + batchSize - 1;
        _sequentialOwnership.push(last, uint160(to));

        // The invariant required by this function is preserved because the new sequentialOwnership checkpoint
        // is attributing ownership of `batchSize` new tokens to account `to`.
        _increaseBalance(to, batchSize);

        emit ConsecutiveTransfer(next, last, address(0), to);
    }

    return next;
}

