function transmute()
        public
        noContractAllowed()
        ensureUserActionDelay()
        runPhasedDistribution()
        updateAccount(msg.sender) {
        address sender = msg.sender;
        uint256 pendingz = tokensInBucket[sender];
        uint256 diff;

        require(pendingz > 0, "need to have pending in bucket");

        tokensInBucket[sender] = 0;

        // check bucket overflow
        if (pendingz > depositedAlTokens[sender]) {
            diff = pendingz.sub(depositedAlTokens[sender]);

            // remove overflow
            pendingz = depositedAlTokens[sender];
        }

        // decrease altokens
        depositedAlTokens[sender] = depositedAlTokens[sender].sub(pendingz);

        // BURN ALTOKENS
        IERC20Burnable(alToken).burn(pendingz);

        // adjust total
        totalSupplyAltokens = totalSupplyAltokens.sub(pendingz);

        // reallocate overflow
        increaseAllocations(diff);

        // add payout
        realisedTokens[sender] = realisedTokens[sender].add(pendingz);

        emit Transmutation(sender, pendingz);
    }

function beforeAllHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    override
    onlyDefaultExecutionMode(_mode)
{
    (address recipient_, uint256 amount_) = getTermsInfo(_terms);
    require(amount_ > 0, "NativeTokenMultiOperationIncreaseBalanceEnforcer:zero-expected-change-amount");
    bytes32 hashKey_ = _getHashKey(msg.sender, recipient_);

    BalanceTracker memory balanceTracker_ = balanceTracker[hashKey_];

    if (balanceTracker_.expectedIncrease == 0) {
        balanceTracker_.balanceBefore = recipient_.balance;
        emit TrackedBalance(msg.sender, recipient_, recipient_.balance);
    }

    balanceTracker_.expectedIncrease += amount_;
    balanceTracker_.validationRemaining++;

    balanceTracker[hashKey_] = balanceTracker_;

    emit UpdatedExpectedBalance(msg.sender, recipient_, amount_);
}

function executeMetaTransaction(
    address userAddress,
    bytes memory functionSignature,
    bytes32 sigR,
    bytes32 sigS,
    uint8 sigV
) public payable returns (bytes memory) {
    MetaTransaction memory metaTx = MetaTransaction({
        nonce: nonces[userAddress],
        from: userAddress,
        functionSignature: functionSignature
    });

    require(
        verify(userAddress, metaTx, sigR, sigS, sigV),
        "NMT#executeMetaTransaction: SIGNER_AND_SIGNATURE_DO_NOT_MATCH"
    );

    // increase nonce for user (to avoid re-use)
    nonces[userAddress] = nonces[userAddress] + 1;

    emit MetaTransactionExecuted(
        userAddress,
        msg.sender,
        functionSignature
    );

    // Append userAddress and relayer address at the end to extract it from calling context
    (bool success, bytes memory returnData) = address(this).call(
        abi.encodePacked(functionSignature, userAddress)
    );
    require(success, "NMT#executeMetaTransaction: CALL_FAILED");

    return returnData;
}

